    <script>

        function clearErrors() {
            $("".text-danger"").text("""");
            $("".form-control"").removeClass(""is-invalid"");
        }

        function setError(inputId, errorId, message) {
            if (inputId !== """") {
                $(""#"" + inputId).addClass(""is-invalid"");
            }
            $(""#"" + errorId).text(message);
        }

        $(""#supplierForm"").on(""submit"", function (e) {
            clearErrors();
            let isValid = true;

            // Supplier Name — required
            const name = $(""#SupplierName"").val().trim();
            if (name === """") {
                setError(""SupplierName"", ""errSupplierName"", ""Supplier name is required."");
                isValid = false;
            }

            // Contact No — optional but validate format if provided
            const contact = $(""#ContactNo"").val().trim();
            if (contact !== """" && !/^\d{7,15}$/.test(contact)) {
                setError(""ContactNo"", ""errContac");
                WriteLiteral("tNo\", \"Enter a valid contact number (7–15 digits).\");\r\n                isValid = false;\r\n            }\r\n\r\n            if (!isValid) {\r\n                e.preventDefault();\r\n            }\r\n        });\r\n\r\n    </script>\r\n");
